class Holder {
    private int x = 0;            // plain field
    private volatile boolean ready = false; // volatile flag

    void publisher() {
        x = 42;                  // (1) plain write
        ready = true;            // (2) volatile write
    }

    int consumer() {
        if (ready) {             // (3) volatile read
            return x;            // (4) guaranteed to see 42, not 0
        }
        return -1;
    }
}
// (1) happens-before (2) by program order;
// (2) happens-before (3) by the volatile rule when (3) reads true;
// (3) happens-before (4) by program order; therefore (1) hb (4).

private final ReentrantLock lock = new ReentrantLock();

boolean transfer(Account to, long amount, Duration timeout)
        throws InterruptedException {
    if (lock.tryLock(timeout.toMillis(), TimeUnit.MILLISECONDS)) {
        try {
            // critical section: guaranteed visibility + exclusion
            balance -= amount;
            to.deposit(amount);
            return true;
        } finally {
            lock.unlock(); // ALWAYS unlock in finally
        }
    }
    return false; // gave up rather than block forever -> avoids deadlock
}

