import java.util.concurrent.locks.*;

public class BoundedBlockingQueue<E> {
    private final E[] buf;
    private int head = 0, tail = 0, count = 0;
    private final ReentrantLock lock = new ReentrantLock();
    private final Condition notFull  = lock.newCondition();
    private final Condition notEmpty = lock.newCondition();

    @SuppressWarnings("unchecked")
    public BoundedBlockingQueue(int capacity) {
        if (capacity <= 0) throw new IllegalArgumentException("capacity > 0");
        this.buf = (E[]) new Object[capacity];
    }

    public void put(E e) throws InterruptedException {
        if (e == null) throw new NullPointerException();
        lock.lockInterruptibly();
        try {
            while (count == buf.length) {   // while, not if
                notFull.await();            // releases lock, parks thread
            }
            buf[tail] = e;
            tail = (tail + 1) % buf.length;
            count++;
            notEmpty.signal();             // wake one waiting consumer
        } finally {
            lock.unlock();
        }
    }

    public E take() throws InterruptedException {
        lock.lockInterruptibly();
        try {
            while (count == 0) {           // while, not if
                notEmpty.await();
            }
            E e = buf[head];
            buf[head] = null;             // help GC
            head = (head + 1) % buf.length;
            count--;
            notFull.signal();             // wake one waiting producer
            return e;
        } finally {
            lock.unlock();
        }
    }

    public int size() {
        lock.lock();
        try { return count; } finally { lock.unlock(); }
    }
}

import java.util.concurrent.atomic.*;

// (A) Correct, simple, best under LOW/MODERATE contention:
public final class AtomicCounter {
    private final AtomicLong value = new AtomicLong();
    public void increment() { value.incrementAndGet(); } // CAS retry loop
    public long sum()        { return value.get(); }     // exact, lock-free
}

// (B) Correct, best under HIGH write contention:
public final class StripedCounter {
    private final LongAdder adder = new LongAdder();
    public void increment() { adder.increment(); }       // updates a per-thread cell
    public long sum()        { return adder.sum(); }     // adds all cells; not
                                                         // atomic vs concurrent writes
}

